sql:
SELECT status, COUNT(*) as Number_of_Users
FROM user_accounts
GROUP BY status;

SELECT max_temp AS Highest_Temperature
FROM temperature_records
WHERE observation_id = 1;

SELECT ws.*
FROM weather_stations ws
INNER JOIN data_quality_checks dqc ON ws.station_id = dqc.observation_id;

SELECT max_temp
FROM temperature_records
WHERE observation_id = 2;

SELECT alert_type, COUNT(*) AS number_of_alerts
FROM weather_alerts
GROUP BY alert_type;

SELECT first_name || ' ' || last_name AS full_name, role
FROM user_accounts
WHERE email LIKE '%@gmail.com';

SELECT ws.contact_email 
FROM weather_stations ws
WHERE ws.elevation > 2000;

SELECT alert_id
FROM weather_alerts
WHERE alert_type = 'heat advisory';

external_knowledge:
- "elevated stations" refers to stations whose elevation is above the average elevation of all stations;
- "high moisture stress" indicates that the humidity level is above 50%;
- "serious warnings" imply that the severity of alerts is 'high';
- "in the recent past" means the alerts were issued within the last 30 days.

sql:
SELECT u.username, w.station_name
FROM user_accounts u
JOIN weather_stations w ON u.username = w.contact_email;

SELECT location 
FROM weather_forecasts 
WHERE forecast_id > 5;
